import React, { useState } from 'react';
import styles from './TheEditSection.module.css';

import men1 from './assets/images/11.jpg';
import men2 from './assets/images/10.jpg';
import men3 from './assets/images/12.jpg';

const mensProducts = [
  {
    id: 1,
    name: 'CROSSBODY BAG (STONE)',
    price: '289,000 KRW',
    bg: '#dddad3',
    imageUrl: men1,
  },
  {
    id: 2,
    name: 'LAPEL JACKET (BLACK)',
    price: '315,000 KRW',
    bg: '#e0ddd6',
    imageUrl: men2,
  },
  {
    id: 3,
    name: 'WIDE LEG TROUSERS (GREY)',
    price: '198,000 KRW',
    bg: '#d5d2cb',
    imageUrl: men3,
  },
];

function ProductCard({ product }) {
  const [hovered, setHovered] = useState(false);

  return (
    <div
      className={styles.card}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
    >
      <div className={styles.imageWrap} style={{ background: product.bg }}>
        <img
          src={product.imageUrl || productImg}
          alt={product.name}
          className={styles.productShape}
        />
        <div
          className={`${styles.hoverOverlay} ${hovered ? styles.hoverVisible : ''}`}
        >
          <p className={styles.hoverName}>{product.name}</p>
          <p className={styles.hoverPrice}>{product.price}</p>
        </div>
      </div>
    </div>
  );
}

function MensEditSection() {
  return (
    <section className={styles.section}>
      <div className={styles.sectionHeader}>
        <h2 className={styles.sectionTitle}>THE EDIT</h2>
        <a href="#!" className={styles.viewAll}>
          view all
        </a>
      </div>
      <div className={styles.grid}>
        {mensProducts.map((product) => (
          <ProductCard key={product.id} product={product} />
        ))}
      </div>
    </section>
  );
}

export default MensEditSection;
